class Uyelik:
    def __init__(self):
        self.durum = "Aktif"

class PremiumUyelik(Uyelik):
    def __init__(self):
        super().__init__()
        self.seviye = "Premium"

    def etiket(self):
        return f"{self.seviye} / {self.durum}"

uyelik = PremiumUyelik()
print(uyelik.etiket())

class Bildirim:
    def gonder(self):
        return "Genel bildirim gönderildi."

class SmsBildirim(__BASE_CLASS__):
    def gonder(self):
        return __SMS_METNI__

bildirim = SmsBildirim()
print(bildirim.gonder())

class Urun:
    def __init__(self, ad):
        self.ad = ad

class IndirimliUrun(Urun):
    def __init__(self, ad, oran):
        self.oran = oran

    def etiket(self):
        return f"{self.ad} - %{self.oran}"

urun = IndirimliUrun("Defter", 20)
print(urun.etiket())

